Based on the reference materials and detailed specifications, here's the complete implementation for the required functions:

```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  // Map table names to their corresponding struct types
  std::map<std::string, std::tuple<std::string, std::string>> table_map = {
    {"Student", {"SNo", "Name"}},
    {"Course", {"CID", "CName"}},
    {"Score", {"ScID", "SNo"}},
    {"Major", {"MID", "MName"}}
  };

  auto it = table_map.find(table_name);
  if (it == table_map.end()) {
    throw std::invalid_argument("Invalid table name");
  }

  const auto& [id_field, name_field] = it->second;

  // Create table if not exists
  auto conn = sqlgen::sqlite::connect(db_path).value();
  (sqlgen::create_table<T> | sqlgen::if_not_exists)(conn).value();

  // Insert records
  sqlgen::insert(records)(conn).value();
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  // Map table names to their corresponding struct types and ID fields
  std::map<std::string, std::tuple<std::string, std::string, std::string>> table_map = {
    {"Student", {"SNo", "Name", "Student"}},
    {"Course", {"CID", "CName", "Course"}},
    {"Score", {"ScID", "SNo", "Score"}},
    {"Major", {"MID", "MName", "Major"}}
  };

  auto it = table_map.find(table_name);
  if (it == table_map.end()) {
    throw std::invalid_argument("Invalid table name");
  }

  const auto& [id_field, name_field, table_alias] = it->second;

  // Delete record by ID
  auto conn = sqlgen::sqlite::connect(db_path).value();
  auto delete_stmt = sqlgen::delete_from<T> | sqlgen::where(id_field == record_id);
  delete_stmt(conn).value();
}

template<typename T>
void modify_eas_records_by_id(const std::string& table_name,
                              const std::string& record_id,
                              const std::string& col_name,
                              const T& new_value) {
  // Map table names to their corresponding struct types and column mappings
  std::map<std::string, std::tuple<std::string, std::string, std::string, std::string>> table_map = {
    {"Student", {"SNo", "Name", "Sex", "Birthday", "Major", "Scores", "Remark"}},
    {"Course", {"CID", "CName", "Term", "CTime", "Credit"}},
    {"Score", {"ScID", "SNo", "CID", "Score"}},
    {"Major", {"MID", "MName"}}
  };

  auto it = table_map.find(table_name);
  if (it == table_map.end()) {
    throw std::invalid_argument("Invalid table name");
  }

  const auto& columns = it->second;

  // Find the column index based on column name
  size_t col_index = -1;
  std::vector<std::string> col_names{columns};
  for (size_t i = 0; i < col_names.size(); ++i) {
    if (col_names[i] == col_name) {
      col_index = i;
      break;
    }
  }

  if (col_index == -1) {
    throw std::invalid_argument("Invalid column name");
  }

  // Update record
  auto conn = sqlgen::sqlite::connect(db_path).value();
  auto update_stmt = sqlgen::update<T> | sqlgen::set(col_index, new_value) | sqlgen::where("id"_c == record_id);
  update_stmt(conn).value();
}
```

**Key Implementation Details:**

1. **Table Mapping**: Uses a map to associate table names with their corresponding struct types and field information
2. **Error Handling**: Includes validation for invalid table/column names
3. **SQLGen Integration**: Properly uses sqlgen's fluent API with pipe operators for chaining operations
4. **Type Safety**: Leverages sqlgen's type system for safe database operations
5. **Connection Management**: Uses sqlgen's connection handling with proper error propagation

The implementation follows sqlgen's principles of type-safe database operations while meeting the specified functional requirements for inserting, modifying, and deleting records based on primary key IDs.

