 */
std::vector<CourseStats> query_course_enrollment_stats() {
  using namespace sqlgen::literals;

  // 1. Connect to the database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // 2. Create tables with transaction for data integrity
  conn->begin_transaction();

  // Create Course table
  auto create_course = sqlgen::create_table<Course> | sqlgen::if_not_exists;
  create_course(*conn);

  // Create Enrollment table  
  auto create_enrollment = sqlgen::create_table<Enrollment> | sqlgen::if_not_exists;
  create_enrollment(*conn);

  // 3. Build and execute the query using sqlgen's fluent interface
  auto query = sqlgen::select_from<Course, "c">(
      "title"_c,
      sqlgen::count().as<"student_count">(),
      sqlgen::avg("grade"_c).as<"avg_grade">()
  )
  | sqlgen::left_join<Enrollment, "e">("c.course_id"_c == "e.course_id"_c)
  | sqlgen::group_by("title"_c, "c.course_id"_c)
  | sqlgen::to<std::vector<CourseStats>>;

  auto result = query(*conn).value();

  // 4. Commit transaction and return results
  conn->commit();

  return result;
}

}  // namespace query_course_enrollment_stats
