 */
std::vector<DailyTraffic> query_daily_traffic_metrics() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // 2. Build the query using sqlgen
  auto query = select_from<PageVisit>(
      // Extract date from visit_time using strftime and alias as "visit_date"
      strftime("%Y-%m-%d", "visit_time"_c).as<"visit_date">,
      // Count total visits
      count().as<"total_visits">,
      // Count distinct URLs
      count_distinct("url"_c).as<"unique_pages">
  )
  // 3. Group by the extracted date
  | group_by("visit_date"_c)
  // 4. Order by date
  | order_by("visit_date"_c);

  // 5. Execute the query and map results to DailyTraffic
  auto result = query(conn);

  // Convert the range to vector of DailyTraffic
  std::vector<DailyTraffic> traffic_metrics;
  for (auto& row : result) {
    traffic_metrics.emplace_back(
        std::move(row.visit_date),
        std::move(row.total_visits),
        std::move(row.unique_pages)
    );
  }

  return traffic_metrics;
}

}  // namespace query_daily_traffic_metrics
