bool create_complex_table() {
  // Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }

  // Create table with if_not_exists modifier
  auto create_result = (sqlgen::create_table<UserProfile> | sqlgen::if_not_exists)(*conn_result);

  // Return success status
