std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect();

  // Create tables
  conn | sqlgen::create_table<User> | sqlgen::create_table<Friendship>;

  // Insert data
  conn | sqlgen::insert(users) | sqlgen::insert(friendships);

  // Build and execute query for mutual friends using self-join and subquery
  auto query = sqlgen::select_from<User, "u1">(
      ("username"_t1 | sqlgen::as<"user1_name">),
      ("username"_t2 | sqlgen::as<"user2_name">)
  )
  | sqlgen::inner_join<Friendship, "f1">("user_id"_t1 == "user1_id"_t2)
  | sqlgen::inner_join<Friendship, "f2">("user2_id"_t2 == "user1_id"_t3)
  | sqlgen::inner_join<User, "u2">("user2_id"_t3 == "user_id"_t4)
  | sqlgen::where(("user_id"_t1 < "user_id"_t4) && sqlgen::exists(
      sqlgen::select_from<Friendship, "f3">(
          "user1_id"_t5 == "user_id"_t1 && "user2_id"_t5 == "user_id"_t4
      )
  ))
  | sqlgen::group_by("user_id"_t1, "user_id"_t4)
  | sqlgen::having(sqlgen::count() > 0);

  // Execute query and convert results
  auto result = query(conn).to<std::vector<FriendConnection>>();

  return result;
}

}  // namespace analyze_social_network

