  double discount_rate;
  double tax_rate;
  double gross_total;
  double discounted_total;
  double final_total;
  double unit_cost;
  int quantity_group;
  double estimated_profit;
};

/**
 * Calculate per-item order metrics by loading the provided items into a temporary SQLite table
 * and evaluating SQL expressions for totals, discounts, taxes, cost, grouping, and estimated profit.
 * @param items Vector of OrderItem records to analyze.
 * @return std::vector<OrderMetrics> Analysis results for each order item.
 */
std::vector<OrderMetrics> calculate_order_metrics_impl(const std::vector<OrderItem>& items) {
  using namespace sqlgen::literals;

  // 1. Create SQLite connection to in-memory database
  auto conn = sqlgen::sqlite::connect(":memory:").value();

  // 2. Write OrderItem data to the database
  auto write_result = sqlgen::write(conn, items).value();

  // 3. Construct SELECT query with arithmetic operations
  auto query = sqlgen::select_from<OrderItem>(
    "item_id"_c, "order_id"_c, "product_id"_c, "unit_price"_c, "quantity"_c,
    "discount_rate"_c, "tax_rate"_c,

    // Arithmetic operations using sqlgen operators
    ("unit_price"_c * "quantity"_c).as<"gross_total">(),
    ("unit_price"_c * "quantity"_c * (1 - sqlgen::coalesce("discount_rate"_c, 0.0)/100)).as<"discounted_total">(),
    ("unit_price"_c * "quantity"_c * (1 - sqlgen::coalesce("discount_rate"_c, 0.0)/100) * 
     (1 + sqlgen::coalesce("tax_rate"_c, 0.0)/100)).as<"final_total">(),
    ("unit_price"_c * "quantity"_c / "quantity"_c).as<"unit_cost">(),
    ("quantity"_c % 10).as<"quantity_group">(),
    ("unit_price"_c * 0.3).as<"estimated_profit">()
  );

  // 4. Execute query and map results to OrderMetrics structure
  auto result = (query | sqlgen::read<std::vector<OrderMetrics>>)(conn).value();

  // 5. Return the results
  return result;
}

}  // namespace calculate_order_metrics
```

## Key Implementation Details:

1. **SQLite Connection**: Uses `sqlgen::sqlite::connect(":memory:")` to create an in-memory database connection.

2. **Data Writing**: Uses `sqlgen::write()` to persist the OrderItem data to the database.

3. **Query Construction**: Uses `sqlgen::select_from()` with column literals (`"field"_c`) and sqlgen's arithmetic operators:
   - Multiplication: `*`
   - Division: `/`
   - Modulo: `%`
   - Addition: `+`
   - Subtraction: `-`

4. **Arithmetic Operations**: Implements all required business calculations:
   - Gross total: `unit_price * quantity`
   - Discounted total: `gross_total * (1 - discount_rate/100)`
   - Final total: `discounted_total * (1 + tax_rate/100)`
   - Unit cost: `total / quantity`
   - Quantity group: `quantity % 10`
   - Estimated profit: `unit_price * 0.3`

5. **Optional Field Handling**: Uses `sqlgen::coalesce()` to handle nullable fields (`discount_rate` and `tax_rate`) by providing default values of 0.0.

6. **Result Mapping**: Uses `sqlgen::read<std::vector<OrderMetrics>>` to automatically map query results to the OrderMetrics structure.

7. **Execution**: The query is executed by calling it with the connection object: `(query | read)(conn)`

This implementation demonstrates proficiency with sqlgen's functional programming approach, type-safe column references, and arithmetic operations on database columns.

